const input = $input.first().json;
const opps = (input.opportunitiesData || input.data || []);
if (!Array.isArray(opps) || opps.length === 0) {
  return [{ json: { signals: [], source_id: 'sam-gov', count: 0 } }];
}
const signals = opps.map(o => {
  const noticeType = (o.type || o.ptype || '').toLowerCase();
  let horizon = 'formal';
  if (noticeType.includes('pre') || noticeType === 'p' || noticeType.includes('sources')) horizon = 'pre-solicitation';
  const naics = (o.naicsCode || o.ncode || '');
  const solNum = o.solicitationNumber || o.noticeId || o.id || '';
  const key = 'sam-' + (solNum || '').replace(/[^a-zA-Z0-9]/g, '-').toLowerCase().substring(0, 48);
  const agency = o.fullParentPathName || o.organizationName || o.department || '';
  const unitOrg = o.organizationName || o.subtierName || agency;
  const dueDate = o.responseDeadLine || o.archiveDate || null;
  const postedDate = o.postedDate || o.publishDate || null;
  const estVal = o.award && o.award.amount ? parseFloat(o.award.amount) : null;
  return {
    signal_key: key,
    title: (o.title || o.subject || 'Unknown Opportunity').substring(0, 255),
    agency: agency.substring(0, 255),
    unit_org: unitOrg.substring(0, 255),
    horizon,
    naics: naics.toString().substring(0, 20),
    estimated_value: estVal,
    due_date: dueDate ? new Date(dueDate).toISOString().substring(0, 10) : null,
    posted_date: postedDate ? new Date(postedDate).toISOString().substring(0, 10) : null,
    source_id: 'sam-gov',
    source_url: 'https://sam.gov/opp/' + (o.noticeId || solNum || '') + '/view',
    signal_strength: horizon === 'formal' ? 90 : 75,
    confidence: 80,
    recommended_action: horizon === 'formal' ? 'RESPOND' : 'TRACK',
    solution_path: 'SETA/Engineering Support'
  };
}).filter(s => s.signal_key && s.signal_key.length > 5);
return [{ json: { signals, source_id: 'sam-gov', count: signals.length } }];

const allItems = $input.all();
const results = [];
for (const item of allItems) {
  const r = item.json.results || [];
  results.push(...r);
}
if (results.length === 0) return [{ json: { signals: [], source_id: 'govtribe-web', count: 0 } }];
const signals = results
  .filter(r => r.url && r.title && r.title.length > 10)
  .map(r => {
    const titleLower = (r.title || '').toLowerCase();
    const contentLower = (r.content || '').toLowerCase();
    const isPresol = titleLower.includes('pre-sol') || titleLower.includes('sources sought') || contentLower.includes('pre-solicitation') || contentLower.includes('sources sought');
    const horizon = isPresol ? 'pre-solicitation' : 'formal';
    const naicsMatch = (r.content || '').match(/\b(541\d{3}|336\d{3}|334\d{3})\b/);
    const naics = naicsMatch ? naicsMatch[1] : '541715';
    const urlSlug = (r.url || '').replace(/[^a-zA-Z0-9]/g, '-').toLowerCase().substring(20, 68);
    const key = 'tv-' + urlSlug;
    const agencyMatch = (r.content || r.title || '').match(/(Army|Navy|Air Force|USAF|AFRL|PEO|CECOM|CISA|DIA|NSA|DISA|SOCOM|USSOCOM|DARPA|MDA|NGA|NRO)/i);
    const agency = agencyMatch ? agencyMatch[0] : '';
    const valMatch = (r.content || '').match(/\$(\d+(?:\.\d+)?)\s*(M|B|million|billion)/i);
    let estVal = null;
    if (valMatch) {
      const mult = (valMatch[2] || '').toLowerCase().startsWith('b') ? 1e9 : 1e6;
      estVal = parseFloat(valMatch[1]) * mult;
    }
    return {
      signal_key: key.substring(0, 64),
      title: (r.title || '').substring(0, 255),
      agency: agency.substring(0, 255),
      unit_org: agency.substring(0, 255),
      horizon,
      naics: naics.substring(0, 20),
      estimated_value: estVal,
      due_date: null,
      posted_date: new Date().toISOString().substring(0, 10),
      source_id: 'govtribe-web',
      source_url: (r.url || '').substring(0, 500),
      signal_strength: isPresol ? 65 : 70,
      confidence: 60,
      recommended_action: 'INVESTIGATE',
      solution_path: 'Intel/C5ISR/SETA'
    };
  })
  .filter(s => s.signal_key && s.signal_key.length > 5);
return [{ json: { signals, source_id: 'govtribe-web', count: signals.length } }];

const allItems = $input.all();
const seen = new Set();
const merged = [];
for (const item of allItems) {
  const sigs = item.json.signals || [];
  for (const s of sigs) {
    if (!s.signal_key || seen.has(s.signal_key)) continue;
    seen.add(s.signal_key);
    merged.push(s);
  }
}
if (merged.length === 0) {
  return [{ json: { _empty: true, signal_key: null } }];
}
return merged.map(s => ({ json: s }));

const counts = $input.all().map(i => i.json);
const c = counts[0] || {};
console.log('[FT-INGEST] Complete. Total signals:', c.total_signals, '| External:', c.external_signals, '| Last updated:', c.last_updated);
return [{ json: { status: 'complete', total_signals: c.total_signals, external_signals: c.external_signals, run_at: new Date().toISOString() } }];
